package hw03.model.strategy;

import java.awt.Graphics;
import java.awt.Point;

import hw03.model.Ball;
import hw03.model.IUpdateStrategy;
import provided.utils.dispatcher.IDispatcher;

/**
 * @author Christina
 * Strategy that reverse the ball every 10 ticks
 */
public class ReverseStrategy implements IUpdateStrategy {
	private int ticks = 0;

	/**
	 * @param disp the dispatcher to communicate
	 * @param ball the ball class
	 */
	public void updateState(IDispatcher<Graphics> disp, Ball ball) {
		ticks++;
		if (ticks > 10) {
			ball.getVelocity().x = -ball.getVelocity().x;
			ball.getVelocity().y = -ball.getVelocity().y;
			ticks = 0;
		}
	}

}

package hw03.model.strategy;

import java.awt.Graphics;

import hw03.model.Ball;
import hw03.model.IUpdateStrategy;
import provided.utils.dispatcher.IDispatcher;

/**
 * @author Christina
 * Ball expands and contracts
 */
public class ExpandingStrategy implements IUpdateStrategy {

	/**
	 * Boolean for whether should expand or not
	 */
	boolean expand = true;
	/**
	 * @param disp the dispatcher to communicate
	 * @param ball the ball class
	 */
	public void updateState(IDispatcher<Graphics> disp, Ball ball) {
		int currentRadius = ball.getRadius();

		if (currentRadius >= 60) {
			expand = false;
		} else if (currentRadius <= 5) {
			expand = true;
		}

		if (expand) {
			currentRadius += 2;
		} else {
			currentRadius -= 2;
		}
		ball.setRadius(currentRadius);
	}
}

